        case 4: return .upperBodyCropped
        
        case 5: return .custom(left: try FfiConverterFloat.read(from: &buf), top: try FfiConverterFloat.read(from: &buf), right: try FfiConverterFloat.read(from: &buf), bottom: try FfiConverterFloat.read(from: &buf)
