        case .upperBodyCropped:
            writeInt(&buf, Int32(4))
        
        
        case let .custom(left,top,right,bottom):
            writeInt(&buf, Int32(5))
            FfiConverterFloat.write(left, into: &buf)
            FfiConverterFloat.write(top, into: &buf)
